function dropNullDates(items, dateField) {
  return items.filter(item => item && item[dateField] != null);
}

function dedupeByKey(items, keyFields, timestampField) {
  const seen = new Map();
  for (const item of items) {
    const key = keyFields.map(f => item[f]).join('|');
    const existing = seen.get(key);
    if (!existing) {
      seen.set(key, item);
    } else if (timestampField) {
      const newTs = item[timestampField];
      const oldTs = existing[timestampField];
      if (newTs != null && (oldTs == null || newTs > oldTs)) {
        seen.set(key, item);
      }
    } else {
      seen.set(key, item);
    }
  }
  return Array.from(seen.values())
    .sort((a, b) => a[keyFields[0]] < b[keyFields[0]] ? 1 : -1);
}

function safeGet(nodeName) {
  try {
    return $(nodeName).all().map(i => i.json);
  } catch (e) {
    return { __missing: nodeName, __error: e.message };
  }
}

function safeGetFirst(nodeName) {
  try {
    return $(nodeName).first().json;
  } catch (e) {
    return { __missing: nodeName, __error: e.message };
  }
}

const healthScoresRaw = safeGet('BigQuery - Health');
const anomaliesRaw = safeGet('BigQuery - Anomalies');
const forecastRaw = safeGet('BigQuery - Forecast');
const briefingRaw = safeGet('BigQuery - Briefing');
const weatherRaw = safeGet('BigQuery - Weather');
const marineRaw = safeGet('BigQuery - Marine');
const airQualityRaw = safeGet('BigQuery - Air');
const weatherWeekRaw = safeGetFirst('Fetch Weather Week Live');
const aqiWeekRaw = safeGetFirst('Fetch AQI Week Live');

const missing = [
  healthScoresRaw, anomaliesRaw, forecastRaw, briefingRaw,
  weatherRaw, marineRaw, airQualityRaw, weatherWeekRaw, aqiWeekRaw
].filter(r => r && r.__missing);

if (missing.length > 0) {
  return [{
    json: {
      error: "One or more node references in the Merge node do not match the canvas.",
      missingNodes: missing.map(m => ({ referenced: m.__missing, detail: m.__error }))
    }
  }];
}

// --- Build the 7-day live forecast ---
let liveForecastWeek = [];
let liveForecastDebug = null;
try {
  const weatherFc = weatherWeekRaw.daily;
  const aqiFc = aqiWeekRaw.hourly;

  if (!weatherFc || !weatherFc.time) {
    liveForecastDebug = { issue: "weatherWeekRaw.daily missing/.time missing", keys: Object.keys(weatherWeekRaw || {}) };
    throw new Error("weather daily data missing");
  }
  if (!aqiFc || !aqiFc.time) {
    liveForecastDebug = { issue: "aqiWeekRaw.hourly missing/.time missing", keys: Object.keys(aqiWeekRaw || {}) };
    throw new Error("aqi hourly data missing");
  }

  const pm25ByDate = {};
  aqiFc.time.forEach((ts, i) => {
    const date = ts.split('T')[0];
    const val = aqiFc.pm2_5 ? aqiFc.pm2_5[i] : null;
    if (val == null) return;
    if (!pm25ByDate[date]) pm25ByDate[date] = [];
    pm25ByDate[date].push(val);
  });

  function scoreDay(tempMax, uvMax, pm25Avg) {
    const tempScore = tempMax < 30 ? 25 : tempMax < 33 ? 20 : tempMax < 37 ? 10 : 0;
    const uvScore = uvMax < 3 ? 25 : uvMax < 6 ? 20 : uvMax < 8 ? 10 : uvMax < 11 ? 5 : 0;
    const aqiScore = pm25Avg == null ? 25 : pm25Avg <= 15 ? 25 : pm25Avg <= 30 ? 15 : 5;
    const humidityScore = 15;
    const total = tempScore + uvScore + aqiScore + humidityScore;
    let label = "Safe";
    if (total < 25) label = "Extreme Risk";
    else if (total < 50) label = "High Risk";
    else if (total < 75) label = "Caution";
    return { total, label };
  }

  liveForecastWeek = weatherFc.time.map((date, i) => {
    const tempMax = weatherFc.temperature_2m_max[i];
    const uvMax = weatherFc.uv_index_max[i];
    const values = pm25ByDate[date] || [];
    const pm25Avg = values.length
      ? Math.round((values.reduce((a, b) => a + b, 0) / values.length) * 100) / 100
      : null;
    const { total, label } = scoreDay(tempMax, uvMax, pm25Avg);
    return {
      for_date: date,
      predicted_temp_max: tempMax,
      predicted_uv_index: uvMax,
      predicted_pm25: pm25Avg,
      predicted_health_score: total,
      predicted_label: label
    };
  });
} catch (e) {
  liveForecastWeek = [{ __error: "Failed to build live forecast: " + e.message, __debug: liveForecastDebug }];
}

return [{
  json: {
    healthScores: dedupeByKey(dropNullDates(healthScoresRaw, 'score_date'), ['score_date'], 'created_at'),
    anomalies: anomaliesRaw,
    forecast: dedupeByKey(dropNullDates(forecastRaw, 'for_date'), ['for_date', 'method'], 'created_at'),
    briefing: dedupeByKey(dropNullDates(briefingRaw, 'briefing_date'), ['briefing_date'], 'created_at')[0] || null,
    weather: dedupeByKey(dropNullDates(weatherRaw, 'fetch_date'), ['fetch_date'], 'ingestion_ts'),
    marine: dedupeByKey(dropNullDates(marineRaw, 'fetch_date'), ['fetch_date'], 'ingestion_ts'),
    airQuality: dedupeByKey(dropNullDates(airQualityRaw, 'fetch_date'), ['fetch_date'], 'ingestion_ts'),
    liveForecastWeek: liveForecastWeek
  }
}];
